 38→// 通用AI调用 (OpenAI兼容格式, Claude单独处理)
 39→function callAI(prompt) {
 40→  return new Promise((resolve) => {
 41→    const cfg = loadAIConfig();
 42→    if (!cfg.apiKey) { resolve(null); return; }
 43→
 44→    const preset = AI_PROVIDERS[cfg.provider] || {};
 45→    const baseUrl = cfg.baseUrl || preset.baseUrl || '';
 46→    const model = cfg.model || preset.model || '';
 47→    if (!baseUrl) { resolve(null); return; }
 48→
 49→    const isClaude = cfg.provider === 'claude';
 50→    const urlObj = new URL(isClaude ? baseUrl + '/messages' : baseUrl + '/chat/completions');
 51→    const isHttps = urlObj.protocol === 'https:';
 52→
 53→    let body, headers;
 54→    if (isClaude) {
 55→      body = JSON.stringify({
 56→        model, max_tokens: 1024,
 57→        messages: [{ role: 'user', content: prompt }]
 58→      });
 59→      headers = {
 60→        'Content-Type': 'application/json',
 61→        'x-api-key': cfg.apiKey,
 62→        'anthropic-version': '2023-06-01'
 63→      };
 64→    } else {
 65→      body = JSON.stringify({
 66→        model, max_tokens: 1024,
 67→        messages: [
 68→          { role: 'system', content: '你是一个多语言学习助手，用中文回答。回答要简洁实用。' },
 69→          { role: 'user', content: prompt }
 70→        ]
 71→      });
 72→      headers = {
 73→        'Content-Type': 'application/json',
 74→        'Authorization': 'Bearer ' + cfg.apiKey
 75→      };
 76→    }
 77→
 78→    const opts = {
 79→      hostname: urlObj.hostname, port: urlObj.port || (isHttps ? 443 : 80),
 80→      path: urlObj.pathname, method: 'POST', headers
 81→    };
 82→
 83→    const client = isHttps ? https : http;
 84→    const req = client.request(opts, (res) => {
 85→      let data = '';
 86→      res.on('data', d => data += d);
 87→      res.on('end', () => {
 88→        try {
 89→          const json = JSON.parse(data);
 90→          if (isClaude) {
 91→            resolve(json.content?.[0]?.text || null);
 92→          } else {
 93→            resolve(json.choices?.[0]?.message?.content || null);
 94→          }
 95→        } catch(e) { resolve(null); }
 96→      });
 97→    });
 98→    req.on('error', () => resolve(null));
 99→    req.setTimeout(15000, () => { req.destroy(); resolve(null); });
100→    req.write(body);
101→    req.end();
102→  });
103→}
