181→// VTT解析 (处理YouTube自动字幕的双行格式)
182→function parseVTT(vtt) {
183→  const raw = [];
184→  for (const block of vtt.split(/\n\n+/)) {
185→    const lines = block.trim().split('\n');
186→    for (let i = 0; i < lines.length; i++) {
187→      const m = lines[i].match(/(\d{2}):(\d{2}):(\d{2})\.(\d{3})\s*-->\s*(\d{2}):(\d{2}):(\d{2})\.(\d{3})/);
188→      if (!m) continue;
189→      const start = +m[1]*3600 + +m[2]*60 + +m[3] + +m[4]/1000;
190→      const end = +m[5]*3600 + +m[6]*60 + +m[7] + +m[8]/1000;
191→      // 跳过极短条目(YouTube自动字幕的过渡帧)
192→      if (end - start < 0.05) break;
193→      // 取最后一行非空文本(YouTube双行字幕中新内容在最后一行)
194→      const textLines = lines.slice(i+1).map(l => l.replace(/<[^>]+>/g, '').trim()).filter(Boolean);
195→      const text = textLines.length > 0 ? textLines[textLines.length - 1] : '';
196→      if (text) raw.push({ start, end, text });
197→      break;
198→    }
199→  }
200→  // 合并连续相同文本，去重
201→  const result = [];
202→  for (const s of raw) {
203→    if (result.length > 0 && result[result.length-1].text === s.text) {
204→      result[result.length-1].end = s.end; // 延长时间
205→    } else {
206→      result.push({ ...s });
207→    }
208→  }
209→  return result;
210→}
