212→// 字幕同步 (用setInterval确保可靠触发)
213→let syncTimer = null;
214→function startSubtitleSync() {
215→  if (syncTimer) clearInterval(syncTimer);
216→  syncTimer = setInterval(() => {
217→    if (!subtitles.length || currentMode !== 'learn' || videoPlayer.paused) return;
218→    const t = videoPlayer.currentTime;
219→    let idx = subtitles.findIndex(s => t >= s.start && t <= s.end);
220→    if (idx < 0) {
221→      idx = subtitles.findIndex(s => s.start > t);
222→      if (idx < 0) idx = subtitles.length - 1;
223→      if (idx > 0 && (t - subtitles[idx-1].end) < (subtitles[idx].start - t)) idx = idx - 1;
224→    }
225→    if (idx !== currentSubIndex) {
226→      currentSubIndex = idx;
227→      currentSentence = subtitles[idx].text;
228→      renderSubtitle(currentSentence);
229→      aiAnalyzeBtn.style.display = 'inline-block';
230→      aiResult.style.display = 'none';
231→      highlightSubtitleList(idx);
232→    }
233→  }, 200);
234→}
