function initRecognition() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) return;
  recognition = new SR();
  recognition.continuous = true;
  recognition.interimResults = true;
  recognition.lang = languages[currentLang]?.tts || 'en-US';
  recognition.onresult = (e) => {
    let text = '';
    for (let i = e.resultIndex; i < e.results.length; i++) text += e.results[i][0].transcript;
    if (text.trim()) {
      currentSentence = text.trim();
      renderSubtitle(currentSentence);
      aiAnalyzeBtn.style.display = 'inline-block';
    }
  };
  recognition.onend = () => { if (useRecognition && !videoPlayer.paused) recognition.start(); };
  recognition.onerror = () => {};
}

function startRecognition() {
  if (!useRecognition) return;
  if (!recognition) initRecognition();
  if (recognition) try { recognition.start(); } catch(e) {}
}

function stopRecognition() {
  if (recognition) try { recognition.stop(); } catch(e) {}
}

videoPlayer.addEventListener('play', () => { if (useRecognition) startRecognition(); });
videoPlayer.addEventListener('pause', stopRecognition);

