// 语音识别生成字幕 (调用本地 funasr 服务)
ipcMain.handle('generate-subtitle', async (_, videoPath) => {
  return new Promise((resolve) => {
    const data = JSON.stringify({ file_path: videoPath });
    const req = http.request({
      hostname: '127.0.0.1', port: 8765, path: '/transcribe',
      method: 'POST', headers: { 'Content-Type': 'application/json' }
    }, (res) => {
      let body = '';
      res.on('data', d => body += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(body);
          if (!json.success || !json.output_path) { resolve(null); return; }
          // 读取 md 文件，提取时间戳行转为 VTT
          const md = fs.readFileSync(json.output_path, 'utf-8');
          const lines = md.split('\n');
          let vtt = 'WEBVTT\n\n';
          const timeRe = /^\[(\d{2}:\d{2}(?::\d{2})?)\]\s*(.+)/;
          const entries = [];
          for (const line of lines) {
            const m = line.match(timeRe);
            if (m) entries.push({ time: m[1], text: m[2].trim() });
          }
          for (let i = 0; i < entries.length; i++) {
            const start = entries[i].time.includes(':') && entries[i].time.split(':').length === 2
              ? '00:' + entries[i].time + '.000'
              : entries[i].time + '.000';
            const end = i + 1 < entries.length
              ? (entries[i+1].time.split(':').length === 2 ? '00:' + entries[i+1].time + '.000' : entries[i+1].time + '.000')
              : start.replace(/(\d{2})\.000$/, (_, s) => String(+s + 5).padStart(2, '0') + '.000');
            vtt += `${start} --> ${end}\n${entries[i].text}\n\n`;
          }
          const vttPath = videoPath.replace(/\.[^.]+$/, '.vtt');
          fs.writeFileSync(vttPath, vtt, 'utf-8');
          resolve(vttPath);
        } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(300000, () => { req.destroy(); resolve(null); });
    req.write(data);
    req.end();
  });
});

