/* 语音识别状态 */
.recognition-status { font-size: 11px; color: #06b6d4; margin-top: 6px; }

/* 单词弹窗 */
.word-popup {
    position: fixed; z-index: 2000; width: 340px; max-height: 400px; overflow-y: auto;
    background: rgba(30,15,50,0.95); backdrop-filter: blur(20px);
    border: 1px solid rgba(255,107,157,0.3); border-radius: 14px;
    box-shadow: 0 10px 40px rgba(0,0,0,0.6); padding: 15px;
}
.popup-header { display: flex; align-items: center; gap: 8px; margin-bottom: 10px; }
.popup-word { font-size: 20px; font-weight: bold; color: #ff6b9d; }
